// Robust Extraction Logic (Regex + Proxy Support)
const item = $input.item.json;
const html = item.data || '';
let body = {};

const possibleNodeNames = ['AdSniper_Trigger', 'Webhook', 'webhook'];
for (const name of possibleNodeNames) {
    try {
        const nodeData = $(name).item.json;
        if (nodeData && nodeData.body) {
            body = nodeData.body;
            break;
        }
    } catch (e) {}
}

let url = body.product_url || '';

// --- PROXY BYPASS LOGIC ---
let title = body.scraped_title || 'Producto Desconocido';
let description = body.scraped_description || 'Sin descripción disponible.';
let price = 'Consultar';
let image = body.scraped_image || '';

if ((title === 'Producto Desconocido' || description.length < 20) && html && html.length > 100) {
    const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    if (titleMatch) title = titleMatch[1].replace(/\s+/g, ' ').trim();

    const ogDesc = html.match(/<meta[^>]*property=["']og:description["'][^>]*content=["']([\s\S]*?)["']/i);
    if (ogDesc) description = ogDesc[1];

    const ogMatch = html.match(/<meta[^>]*property=["']og:image["'][^>]*content=["']([\s\S]*?)["']/i);
    if (ogMatch) image = ogMatch[1];
}

if (image && image.startsWith('//')) image = 'https:' + image;

return {
  product_url: url,
  title: title,
  price: price,
  description: description.substring(0, 3000),
  main_image: image
};

const ads = $('AdSniper AI Generator').item.json.output || [];
let brand = {};
const possibleNodeNames = ['AdSniper_Trigger', 'Webhook', 'webhook'];
for (const name of possibleNodeNames) {
    try {
        const nodeData = $(name).item.json;
        if (nodeData && nodeData.body && nodeData.body.brand) {
            brand = nodeData.body.brand;
            break;
        }
    } catch (e) {}
}
return {
    ads: ads,
    brand: brand
};
